    # --- Phase 2: Chain moves (2-step ejection chains) ---
    def try_chain_moves(current):
        """Try 2-step chain moves: move model from worst to X, then move from X to Y."""
        grate = [0.0] * gpu_num
        gsize = [0] * gpu_num
        for i in range(n):
            g = current[i]
            grate[g] += rates[i]
            gsize[g] += sizes[i]

        def get_max_all():
            mx = 0.0
            for g in range(gpu_num):
                rem = GPU_MEM_SIZE - gsize[g]
                if rem <= 0:
                    return float('inf')
                k = grate[g] / rem
                if k > mx:
