            return mx

        improved = True
        while improved:
            improved = False
            cur_max = get_max_all()
            worst_g = 0
            worst_k = 0.0
            for g in range(gpu_num):
                rem = GPU_MEM_SIZE - gsize[g]
                k = grate[g] / rem if rem > 0 else float('inf')
                if k > worst_k:
