                    worst_g = g

            # Models on worst GPU
            worst_models = [i for i in range(n) if current[i] == worst_g]

            best_chain_max = cur_max
            best_chain = None

            for i in worst_models:
                for mid_g in range(gpu_num):
                    if mid_g == worst_g:
                        continue
                    if gsize[mid_g] + sizes[i] >= GPU_MEM_SIZE:
                        continue

                    # After moving i: worst_g → mid_g
                    # Now find a model j on mid_g to move to another GPU
                    mid_models = [j for j in range(n) if current[j] == mid_g and j != i]

                    for j in mid_models:
                        for dst_g in range(gpu_num):
                            if dst_g == mid_g:
                                continue
                            if gsize[dst_g] + sizes[j] >= GPU_MEM_SIZE:
                                continue
                            if dst_g == worst_g and gsize[worst_g] - sizes[i] + sizes[j] >= GPU_MEM_SIZE:
                                continue

                            # Compute new KVPR for all affected GPUs
                            # worst_g loses i, potentially gains j
                            nsize_w = gsize[worst_g] - sizes[i] + (sizes[j] if dst_g == worst_g else 0)
                            nrate_w = grate[worst_g] - rates[i] + (rates[j] if dst_g == worst_g else 0)
                            if nsize_w >= GPU_MEM_SIZE:
                                continue
                            nk_w = nrate_w / (GPU_MEM_SIZE - nsize_w) if nrate_w > 0 else 0.0

                            # mid_g gains i, loses j
                            nsize_m = gsize[mid_g] + sizes[i] - sizes[j]
                            nrate_m = grate[mid_g] + rates[i] - rates[j]
                            if nsize_m >= GPU_MEM_SIZE:
                                continue
                            nk_m = nrate_m / (GPU_MEM_SIZE - nsize_m) if nrate_m > 0 else 0.0

                            # dst_g gains j (unless dst_g == worst_g, handled above)
                            if dst_g != worst_g:
                                nsize_d = gsize[dst_g] + sizes[j]
                                nrate_d = grate[dst_g] + rates[j]
                                if nsize_d >= GPU_MEM_SIZE:
                                    continue
                                nk_d = nrate_d / (GPU_MEM_SIZE - nsize_d)
                            else:
                                nk_d = nk_w  # already computed

                            new_max = max(nk_w, nk_m, nk_d)
                            if new_max >= best_chain_max:
                                continue

                            # Check other GPUs
                            skip = False
                            for g2 in range(gpu_num):
                                if g2 == worst_g or g2 == mid_g or g2 == dst_g:
                                    continue
                                if grate[g2] > 0:
                                    k2 = grate[g2] / (GPU_MEM_SIZE - gsize[g2])
                                    new_max = max(new_max, k2)
                                    if new_max >= best_chain_max:
                                        skip = True
                                        break
                            if not skip and new_max < best_chain_max:
                                best_chain_max = new_max
                                best_chain = (i, mid_g, j, dst_g)

            if best_chain is not None and best_chain_max < cur_max - 1e-15:
                i, mid_g, j, dst_g = best_chain
                # Execute chain: move i from worst_g to mid_g, move j from mid_g to dst_g
                grate[worst_g] -= rates[i]
                gsize[worst_g] -= sizes[i]
                grate[mid_g] += rates[i]
                gsize[mid_g] += sizes[i]
                current[i] = mid_g

                grate[mid_g] -= rates[j]
                gsize[mid_g] -= sizes[j]
                grate[dst_g] += rates[j]
                gsize[dst_g] += sizes[j]
                current[j] = dst_g
                improved = True

        return current, get_max_all()

    current, cur_kvpr = try_chain_moves(list(best_assignment))
    if cur_kvpr < best_kvpr:
        best_kvpr = cur_kvpr
        best_assignment = list(current)
        # Run standard local search again after chain improvement
        current, cur_kvpr = local_search(list(best_assignment))
        if cur_kvpr < best_kvpr:
