            best_assignment = list(current)

    # --- Phase 3: All-pairs moves/swaps (not just from worst) ---
    def all_pairs_search(current):
        """Try moves and swaps between ALL pairs of GPUs."""
        grate = [0.0] * gpu_num
        gsize = [0] * gpu_num
        for i in range(n):
            g = current[i]
            grate[g] += rates[i]
            gsize[g] += sizes[i]

        def get_max_all():
            mx = 0.0
            for g in range(gpu_num):
