    # --- Phase 4: Iterated Local Search with perturbation ---
    def perturb(current, strength=3):
        """Random perturbation: move `strength` random models to random valid GPUs."""
        perm = list(range(n))
        random.shuffle(perm)
        new_curr = list(current)
        gpu_size_tmp = [0] * gpu_num
        for i in range(n):
