        worst_models = [i for i in range(n) if current[i] == worst_g]
        for i in worst_models:
            for j in range(n):
                if current[j] == worst_g:
                    continue
                g2 = current[j]
                for k in range(n):
                    if k == j or current[k] == worst_g or current[k] == g2:
                        continue
                    g3 = current[k]
                    # Rotation: i goes to g2, j goes to g3, k goes to worst_g
                    ns_w = gsize[worst_g] - sizes[i] + sizes[k]
                    ns_2 = gsize[g2] - sizes[j] + sizes[i]
