                    nk_w = (grate[worst_g] - rates[i] + rates[k]) / (GPU_MEM_SIZE - ns_w)
                    nk_2 = (grate[g2] - rates[j] + rates[i]) / (GPU_MEM_SIZE - ns_2)
                    nk_3 = (grate[g3] - rates[k] + rates[j]) / (GPU_MEM_SIZE - ns_3)
                    new_max = max(nk_w, nk_2, nk_3)
